+// Filter with inverted range (NOT BETWEEN): returns indices where val < low OR val > high
+export fn filterFloat64NotRange(
+    data_ptr: [*]const f64,
+    len: usize,
+    low: f64,
+    high: f64,
+    out_indices: [*]u32,
+    max_indices: usize,
+) usize {
+    var out_count: usize = 0;
+    for (0..len) |i| {
+        if (out_count >= max_indices) break;
+        const v = data_ptr[i];
+        if (v < low or v > high) {
+            out_indices[out_count] = @intCast(i);
+            out_count += 1;
+        }
+    }
+    return out_count;
+}
